parameters.jsCode:
const invoice = $input.first().json;
const tolerance = $('Workflow Configuration').first().json.validationTolerance;

// Recalculate line totals
let calculatedSubtotal = 0;
const validatedLineItems = [];

for (const item of invoice.lineItems || []) {
  const calculatedAmount = (item.quantity || 0) * (item.rate || 0);
  const amountMatch = Math.abs(calculatedAmount - (item.amount || 0)) <= tolerance;

  validatedLineItems.push({
    ...item,
    calculatedAmount,
    amountMatch
  });

  calculatedSubtotal += calculatedAmount;
}

// Recalculate tax and total
const calculatedTax = calculatedSubtotal * ((invoice.taxRate || 0) / 100);
const calculatedTotal = calculatedSubtotal + calculatedTax;

// Validation checks
const subtotalMatch = Math.abs(calculatedSubtotal - (invoice.subtotal || 0)) <= tolerance;
const taxMatch = Math.abs(calculatedTax - (invoice.taxAmount || 0)) <= tolerance;
const totalMatch = Math.abs(calculatedTotal - (invoice.total || 0)) <= tolerance;

const validationPassed = subtotalMatch && taxMatch && totalMatch;

return {
  json: {
    ...invoice,
    lineItems: validatedLineItems,
    validation: {
      calculatedSubtotal,
      calculatedTax,
      calculatedTotal,
      subtotalMatch,
      taxMatch,
      totalMatch,
      validationPassed,
      tolerance
    }
  }
};

const invoice = $input.first().json;

// PII masking functions
function maskPAN(pan) {
  if (!pan || pan.length < 10) return pan;
  return 'XXXX-XXXX-' + pan.slice(-4);
}

function maskBankAccount(account) {
  if (!account || account.length < 4) return account;
  return 'XXXX-XXXX-' + account.slice(-4);
}

function maskGST(gst) {
  if (!gst || gst.length < 6) return gst;
  return 'XXXX-XXXX-' + gst.slice(-6);
}

// Store original values (encrypted in production)
const originalPII = {
  vendorPAN: invoice.vendorPAN,
  vendorBankAccount: invoice.vendorBankAccount,
  vendorGST: invoice.vendorGST
};

// Apply masking
const maskedInvoice = {
  ...invoice,
  vendorPAN: maskPAN(invoice.vendorPAN),
  vendorBankAccount: maskBankAccount(invoice.vendorBankAccount),
  vendorGST: maskGST(invoice.vendorGST),
  _originalPII: originalPII,
  _piiMasked: true
};

return { json: maskedInvoice };

